
"use client"

import React, { useEffect, useMemo, memo, useState, useCallback } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import dynamic from 'next/dynamic';
import { 
  LayoutDashboard, 
  LineChart, 
  LogOut, 
  Activity,
  PieChart,
  User,
  Newspaper,
  History,
  Crown,
  Zap,
  Globe,
  Loader2,
  RefreshCw,
  Palette,
  Menu,
  X
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { 
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { WhatsAppButton } from '@/components/WhatsAppButton';
import { SignalCard } from '@/components/SignalCard';
import { Paywall } from '@/components/Paywall';
import { AdminPanel } from '@/components/AdminPanel';
import { useTradingSignals } from '@/hooks/use-trading-signals';
import { useUser, useAuth, useFirestore, useCollection, useMemoFirebase } from '@/firebase';
import { query, collection, orderBy, limit } from 'firebase/firestore';
import { signOut } from 'firebase/auth';
import { cn } from '@/lib/utils';

const NewsTimeline = dynamic(() => import('@/components/tradingview/NewsTimeline').then(mod => mod.NewsTimeline), { ssr: false });

export default function DashboardPage() {
  const router = useRouter();
  const auth = useAuth();
  const db = useFirestore();
  const { user, isUserLoading } = useUser();
  const { 
    signals, 
    fetchSignal, 
    unlockSignal,
    viewedSignalIds,
    loading,
    isVip,
    signalsUsed,
    isSyncing
  } = useTradingSignals();
  
  const [mounted, setMounted] = useState(false);
  const [paywallOpen, setPaywallOpen] = useState(false);
  const [refreshKey, setRefreshKey] = useState(0);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [theme, setTheme] = useState('cyber');
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    if (mounted) {
      document.documentElement.setAttribute('data-theme', theme);
    }
  }, [theme, mounted]);

  useEffect(() => {
    if (mounted && !isUserLoading && !user) {
      router.replace('/login');
    }
  }, [user, isUserLoading, router, mounted]);

  const liveSignalsQuery = useMemoFirebase(() => {
    if (!db || !user) return null;
    return query(collection(db, 'tradingSignals'), orderBy('createdAt', 'desc'), limit(10));
  }, [db, user?.uid]); // Use uid for stable deps

  const { data: liveSignals, isLoading: liveSignalsLoading } = useCollection(liveSignalsQuery);

  const instruments = useMemo(() => [
    { symbol: 'GOLD', name: 'Gold', type: 'Forex' as const },
    { symbol: 'BTC', name: 'Bitcoin', type: 'Crypto' as const },
    { symbol: 'ETH', name: 'Ethereum', type: 'Crypto' as const },
  ], []);

  // Stabilize callbacks to prevent SignalCard flickering
  const handleFetch = useCallback(async (symbol: string, type: 'Forex' | 'Crypto') => {
    const status = await fetchSignal(symbol, type);
    if (status === 'limit_reached') setPaywallOpen(true);
  }, [fetchSignal]);

  const handleUnlock = useCallback(async (id: string, sig: any) => {
    const success = await unlockSignal(id, sig);
    if (!success && !isVip && signalsUsed >= 7) setPaywallOpen(true);
  }, [unlockSignal, isVip, signalsUsed]);

  const handleOpenPaywall = useCallback(() => {
    setPaywallOpen(true);
  }, []);

  const handleLogout = async () => {
    await signOut(auth);
    router.replace('/login');
  };

  if (!mounted || isUserLoading) {
    return (
      <div className="min-h-screen bg-black flex items-center justify-center">
        <Activity className="h-8 w-8 text-primary animate-spin" />
      </div>
    );
  }

  if (!user) return null;

  return (
    <div className="min-h-screen bg-background text-foreground flex overflow-x-hidden gpu-stable">
      {/* Sidebar Desktop */}
      <aside className="w-64 border-r border-white/5 bg-black/40 backdrop-blur-xl hidden lg:flex flex-col sticky top-0 h-screen gpu-stable">
        <div className="p-6">
          <div className="flex items-center gap-2 text-lg font-black tracking-tighter">
            <LineChart className="h-6 w-6 text-primary" />
            DEEBDATA <span className="text-primary">TRADING</span>
          </div>
        </div>
        
        <nav className="flex-1 px-4 space-y-1">
          <NavItem href="/dashboard" icon={<LayoutDashboard className="h-4 w-4" />} label="Terminal" active />
          <NavItem href="/analysis" icon={<PieChart className="h-4 w-4" />} label="Technical Hub" />
          <NavItem href="/history" icon={<History className="h-4 w-4" />} label="Execution Log" />
          <NavItem href="/profile" icon={<User className="h-4 w-4" />} label="Identity" />
        </nav>

        <div className="p-4 space-y-2">
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="outline" className="w-full justify-start gap-2 text-[10px] font-black uppercase">
                <Palette className="h-4 w-4" /> Switch Theme
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end" className="bg-black border-white/10 text-white">
              <DropdownMenuItem onClick={() => setTheme('cyber')}>Cyber (Default)</DropdownMenuItem>
              <DropdownMenuItem onClick={() => setTheme('deep-sea')}>Deep Sea</DropdownMenuItem>
              <DropdownMenuItem onClick={() => setTheme('midnight')}>Midnight</DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
          
          {!isVip && (
            <Button onClick={handleOpenPaywall} className="w-full h-10 bg-amber-500 hover:bg-amber-600 text-black font-black uppercase text-[10px] rounded-xl animate-pulse-gold">
              <Crown className="h-4 w-4 mr-2" /> Upgrade VIP
            </Button>
          )}
          <Button variant="ghost" className="w-full justify-start gap-3 text-muted-foreground hover:text-destructive h-10" onClick={handleLogout}>
            <LogOut className="h-4 w-4" /> Log Out
          </Button>
        </div>
      </aside>

      {/* Mobile Menu Overlay */}
      {mobileMenuOpen && (
        <div className="fixed inset-0 z-[100] bg-black/90 backdrop-blur-xl flex flex-col p-8 lg:hidden animate-in fade-in duration-300">
           <div className="flex justify-between items-center mb-12">
             <div className="flex items-center gap-2 text-xl font-black">
                <LineChart className="h-6 w-6 text-primary" />
                DEEBDATA <span className="text-primary">TRADING</span>
             </div>
             <Button variant="ghost" size="icon" onClick={() => setMobileMenuOpen(false)}>
               <X className="h-8 w-8" />
             </Button>
           </div>
           <nav className="space-y-6">
              <MobileNavItem href="/dashboard" icon={<LayoutDashboard className="h-6 w-6" />} label="Terminal" />
              <MobileNavItem href="/analysis" icon={<PieChart className="h-6 w-6" />} label="Technical Hub" />
              <MobileNavItem href="/history" icon={<History className="h-6 w-6" />} label="Execution Log" />
              <MobileNavItem href="/profile" icon={<User className="h-6 w-6" />} label="Identity" />
           </nav>
           <div className="mt-auto space-y-4">
              <Button onClick={() => {handleOpenPaywall(); setMobileMenuOpen(false);}} className="w-full h-14 bg-amber-500 text-black font-black text-lg rounded-2xl">
                UPGRADE TO VIP
              </Button>
              <Button onClick={handleLogout} variant="outline" className="w-full h-14 text-destructive border-destructive/20 rounded-2xl font-black">
                LOG OUT
              </Button>
           </div>
        </div>
      )}

      <main className="flex-1 bg-black/20 flex flex-col max-w-full">
        <header className="h-16 border-b border-white/5 flex items-center justify-between px-4 md:px-8 bg-black/40 backdrop-blur-md sticky top-0 z-40">
          <div className="flex items-center gap-4">
            <Button variant="ghost" size="icon" className="lg:hidden" onClick={() => setMobileMenuOpen(true)}>
              <Menu className="h-6 w-6" />
            </Button>
            <h1 className="text-xs font-black uppercase tracking-widest hidden md:block">Market Control</h1>
            
            {!isVip ? (
              <Badge variant="outline" className="text-[8px] font-black uppercase border-white/10 text-amber-500">
                Free ({signalsUsed}/7)
              </Badge>
            ) : (
              <Badge variant="outline" className="text-[8px] font-black uppercase border-amber-500/20 text-amber-500 bg-amber-500/5">
                VIP Member
              </Badge>
            )}
          </div>

          <div className="flex items-center gap-2">
            <Button onClick={() => setRefreshKey(k => k + 1)} variant="ghost" size="sm" className="h-8 w-8 p-0">
              <RefreshCw className={cn("h-4 w-4", refreshKey > 0 && "animate-spin")} />
            </Button>
            <div 
              onClick={() => {
                const count = (window as any).adminClicks || 0;
                (window as any).adminClicks = count + 1;
                if ((window as any).adminClicks >= 7) {
                  setIsAdminOpen(true);
                  (window as any).adminClicks = 0;
                }
              }}
              className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center cursor-pointer"
            >
              <Activity className="h-4 w-4 text-primary animate-pulse" />
            </div>
          </div>
        </header>

        {isSyncing ? (
          <div className="flex-1 flex flex-col items-center justify-center">
            <Loader2 className="h-10 w-10 text-primary animate-spin mb-4" />
            <p className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Synchronizing Terminal Data...</p>
          </div>
        ) : (
          <div className="p-4 md:p-8 space-y-8 flex-1 overflow-x-hidden">
            <div className="grid grid-cols-1 xl:grid-cols-4 gap-8">
              <div className="xl:col-span-3 space-y-8">
                <section className="space-y-4">
                  <div className="flex items-center justify-between">
                    <h2 className="text-lg font-black tracking-tighter uppercase flex items-center gap-2">
                      <Globe className="h-5 w-5 text-accent animate-spin-slow" /> 
                      Live Signals
                    </h2>
                    <Badge className="bg-accent/10 text-accent border-accent/20 text-[8px] font-black uppercase">Institutional</Badge>
                  </div>
                  
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4" key={`live-${refreshKey}`}>
                    {liveSignalsLoading ? (
                      <div className="col-span-full py-12 flex flex-col items-center justify-center">
                        <Loader2 className="h-8 w-8 text-primary animate-spin mb-2" />
                        <p className="text-[9px] font-black uppercase tracking-widest text-muted-foreground">Syncing Live Feed...</p>
                      </div>
                    ) : liveSignals?.map((sig) => (
                      <SignalCard 
                        key={sig.id}
                        symbol={sig.asset}
                        type={sig.asset.includes('BTC') || sig.asset.includes('ETH') ? 'Crypto' : 'Forex'}
                        signal={sig}
                        isLocked={!isVip && !viewedSignalIds.has(sig.id)}
                        onUnlock={() => handleUnlock(sig.id, sig)}
                        onUpgradeClick={handleOpenPaywall}
                      />
                    ))}
                  </div>
                </section>

                <section className="space-y-4">
                  <h2 className="text-lg font-black tracking-tighter uppercase">AI Pulse</h2>
                  <div className="flex gap-2 overflow-x-auto pb-2 custom-scrollbar">
                    {instruments.map(inst => (
                      <Button 
                        key={inst.symbol} 
                        variant="outline" 
                        size="sm" 
                        className="h-9 px-4 text-[10px] font-black uppercase bg-white/5 whitespace-nowrap" 
                        onClick={() => handleFetch(inst.symbol, inst.type)}
                        disabled={loading}
                      >
                        <Zap className="h-3 w-3 mr-2" /> {inst.symbol}
                      </Button>
                    ))}
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {Object.entries(signals).map(([symbol, signal]) => (
                      signal && (
                        <SignalCard 
                          key={symbol}
                          symbol={symbol}
                          type={instruments.find(i => i.symbol === symbol)?.type || 'Forex'}
                          signal={signal}
                          isLocked={false}
                        />
                      )
                    ))}
                  </div>
                </section>
              </div>

              <div className="space-y-4 lg:sticky lg:top-24 h-fit">
                <h3 className="text-[10px] font-black uppercase tracking-widest text-muted-foreground flex items-center gap-2">
                   <Newspaper className="h-4 w-4 text-accent" /> Intelligence
                </h3>
                <div className="rounded-2xl border border-white/5 glassmorphism overflow-hidden h-[400px] md:h-[600px]">
                  <NewsTimeline height="100%" />
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <AdminPanel isOpen={isAdminOpen} onClose={() => setIsAdminOpen(false)} />
      <Paywall isOpen={paywallOpen} onClose={() => setPaywallOpen(false)} />
      <WhatsAppButton />
    </div>
  );
}

const NavItem = memo(({ href, icon, label, active }: { href: string, icon: React.ReactNode, label: string, active?: boolean }) => (
  <Link 
    href={href} 
    className={cn(
      "flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-300",
      active ? 'bg-primary text-white font-bold shadow-lg shadow-primary/20' : 'text-muted-foreground hover:bg-white/5 hover:text-white'
    )}
  >
    {icon} <span className="text-sm font-black uppercase tracking-widest">{label}</span>
  </Link>
));

const MobileNavItem = ({ href, icon, label }: { href: string, icon: React.ReactNode, label: string }) => (
  <Link 
    href={href} 
    className="flex items-center gap-6 px-4 py-4 rounded-2xl bg-white/5 border border-white/5 text-white"
  >
    <div className="text-primary">{icon}</div>
    <span className="text-lg font-black uppercase tracking-widest">{label}</span>
  </Link>
);
