"use client"

import React, { useState, useEffect } from 'react';
import { ShieldCheck, BarChart2, Users, FilePlus2, Lock, Activity, ChevronRight, Loader2, Sparkles, Search, UserCheck, UserX, Trash2 } from 'lucide-react';
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle, 
  DialogDescription 
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { toast } from '@/hooks/use-toast';
import { useFirestore, useCollection, useMemoFirebase } from '@/firebase';
import { collection, addDoc, serverTimestamp, query, getDocs, doc, updateDoc, deleteDoc, orderBy, limit, collectionGroup, where } from 'firebase/firestore';

interface AdminPanelProps {
  isOpen: boolean;
  onClose: () => void;
}

export const AdminPanel = ({ isOpen, onClose }: AdminPanelProps) => {
  const db = useFirestore();
  const [password, setPassword] = useState('');
  const [isAuthorized, setIsAuthorized] = useState(false);
  const [loading, setLoading] = useState(false);
  const [broadcastLoading, setBroadcastLoading] = useState(false);
  const [userSearch, setUserSearch] = useState('');
  const [foundUsers, setFoundUsers] = useState<any[]>([]);
  const [searching, setSearching] = useState(false);

  // Signal Form State
  const [asset, setAsset] = useState('');
  const [direction, setDirection] = useState<'Buy' | 'Sell'>('Buy');
  const [entry, setEntry] = useState('');
  const [tp, setTp] = useState('');
  const [sl, setSl] = useState('');
  const [reason, setReason] = useState('');

  // Live Signals List for Deletion
  const signalsQuery = useMemoFirebase(() => {
    if (!db) return null;
    return query(collection(db, 'tradingSignals'), orderBy('createdAt', 'desc'), limit(15));
  }, [db]);
  const { data: liveSignals } = useCollection(signalsQuery);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    if (password === 'DeebData.Trading@79') {
      setIsAuthorized(true);
      toast({ title: "Authorized", description: "Admin terminal active." });
    } else {
      toast({ title: "Access Denied", description: "Invalid security key.", variant: "destructive" });
    }
    setLoading(false);
  };

  const handleSearchUser = async () => {
    if (!userSearch || !db) return;
    setSearching(true);
    try {
      const results: any[] = [];
      const profilesRef = collectionGroup(db, 'profile');
      const q = query(profilesRef, where('email', '>=', userSearch), where('email', '<=', userSearch + '\uf8ff'));
      const querySnapshot = await getDocs(q);
      
      querySnapshot.forEach((doc) => {
        results.push({ ...doc.data(), uid: doc.id });
      });
      
      setFoundUsers(results);
      if (results.length === 0) toast({ title: "No Traders Found" });
    } catch (e: any) {
      console.error(e);
      toast({ title: "Search Error", description: e.message, variant: "destructive" });
    } finally {
      setSearching(false);
    }
  };

  const toggleUserVip = async (uid: string, currentStatus: boolean) => {
    if (!db) return;
    try {
      const profileRef = doc(db, 'users', uid, 'profile', uid);
      await updateDoc(profileRef, {
        isSubscribed: !currentStatus,
        updatedAt: serverTimestamp()
      });
      toast({ title: "Status Updated", description: `VIP status for trader ${currentStatus ? 'revoked' : 'approved'}.` });
      handleSearchUser();
    } catch (e) {
      toast({ title: "Update Failed", variant: "destructive" });
    }
  };

  const handleDeleteSignal = async (id: string) => {
    if (!db) return;
    try {
      await deleteDoc(doc(db, 'tradingSignals', id));
      toast({ title: "Signal Deleted", description: "Removed from live feed." });
    } catch (e) {
      toast({ title: "Delete Failed", variant: "destructive" });
    }
  };

  const handleBroadcast = async () => {
    if (!db || !asset || !entry || !tp || !sl) {
      toast({ title: "Incomplete Data", variant: "destructive" });
      return;
    }
    setBroadcastLoading(true);
    try {
      await addDoc(collection(db, 'tradingSignals'), {
        asset: asset.toUpperCase(),
        direction,
        entryPrice: parseFloat(entry),
        takeProfit: parseFloat(tp),
        stopLoss: parseFloat(sl),
        reasoning: reason || "Live institutional signal from DeebData Analysts.",
        confidenceScore: 94,
        createdAt: serverTimestamp(),
        isLive: true
      });
      toast({ title: "Signal Broadcasted" });
      setAsset(''); setEntry(''); setTp(''); setSl(''); setReason('');
    } finally {
      setBroadcastLoading(false);
    }
  };

  const handleSeedData = async () => {
    if (!db) return;
    const mockSignals = [
      { asset: 'XAUUSD', direction: 'Buy', entry: 4525.50, tp: 4680.00, sl: 4480.00, reason: 'Massive Gold rally in APRIL 2026 reaching $4500 milestone.' },
      { asset: 'BTCUSD', direction: 'Buy', entry: 292500, tp: 315000, sl: 282000, reason: 'Bitcoin institutional demand peaks in APRIL 2026 cycle.' },
      { asset: 'ETHUSD', direction: 'Buy', entry: 13200.00, tp: 14500.00, sl: 12800.00, reason: 'Ethereum ecosystem dominance driving price to new 2026 highs.' }
    ];
    try {
      for (const sig of mockSignals) {
        await addDoc(collection(db, 'tradingSignals'), {
          ...sig,
          entryPrice: sig.entry,
          takeProfit: sig.tp,
          stopLoss: sig.sl,
          reasoning: sig.reason,
          confidenceScore: 97,
          createdAt: serverTimestamp(),
          isLive: true
        });
      }
      toast({ title: "Analyst Data Seeded with APRIL 2026 Hyper-Bullish Prices" });
    } catch (e) {
      toast({ title: "Seeding Failed", variant: "destructive" });
    }
  };

  if (!isAuthorized) {
    return (
      <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
        <DialogContent className="sm:max-w-md border-white/10 glassmorphism p-8">
          <div className="flex flex-col items-center text-center space-y-6">
            <div className="h-20 w-20 rounded-2xl bg-destructive/10 border border-destructive/30 flex items-center justify-center">
              <Lock className="h-10 w-10 text-destructive" />
            </div>
            <DialogHeader>
              <DialogTitle className="text-2xl font-black uppercase">Admin Restricted</DialogTitle>
              <DialogDescription className="text-xs font-bold text-muted-foreground uppercase tracking-widest">
                Identity Authentication Required
              </DialogDescription>
            </DialogHeader>
            <form onSubmit={handleLogin} className="w-full space-y-4">
              <input
                type="password"
                placeholder="Security Access Key"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full h-14 bg-black/40 border border-white/10 rounded-xl text-center font-bold tracking-widest text-white focus:outline-none focus:ring-2 focus:ring-primary/50"
                autoFocus
              />
              <Button type="submit" className="w-full h-14 bg-destructive text-white font-black" disabled={loading}>
                {loading ? <Activity className="h-5 w-5 animate-spin" /> : 'Enter Secured Terminal'}
              </Button>
            </form>
          </div>
        </DialogContent>
      </Dialog>
    );
  }

  return (
    <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
      <DialogContent className="sm:max-w-5xl max-h-[90vh] overflow-y-auto border-white/10 glassmorphism p-0">
        <div className="p-10 space-y-10">
          <DialogHeader className="flex flex-row items-center justify-between">
            <div className="space-y-1">
              <div className="flex items-center gap-2">
                <ShieldCheck className="h-6 w-6 text-primary" />
                <DialogTitle className="text-3xl font-black uppercase tracking-tighter">DeebData <span className="text-primary">Admin Control</span></DialogTitle>
              </div>
              <p className="text-[10px] text-muted-foreground uppercase font-bold tracking-[0.3em]">Institutional Management Interface</p>
            </div>
          </DialogHeader>

          <Tabs defaultValue="signals" className="w-full">
            <TabsList className="grid w-full grid-cols-2 bg-white/5 border border-white/10 h-12 p-1 rounded-xl mb-8">
              <TabsTrigger value="signals" className="font-black uppercase text-[10px] tracking-widest">Signals Command</TabsTrigger>
              <TabsTrigger value="users" className="font-black uppercase text-[10px] tracking-widest">Trader Identity Hub</TabsTrigger>
            </TabsList>

            <TabsContent value="signals" className="space-y-10">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <Card className="bg-white/5 border-white/10 p-6 space-y-6 rounded-3xl">
                  <h3 className="font-black text-lg uppercase tracking-tight flex items-center gap-2">
                    <FilePlus2 className="h-5 w-5 text-primary" /> Broadcast Signal
                  </h3>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="col-span-1 space-y-1">
                      <label className="text-[8px] font-black uppercase text-muted-foreground ml-1">Symbol</label>
                      <Input value={asset} onChange={(e) => setAsset(e.target.value)} placeholder="XAUUSD" className="bg-black/40 border-white/5 h-12 font-bold" />
                    </div>
                    <div className="col-span-1 space-y-1">
                      <label className="text-[8px] font-black uppercase text-muted-foreground ml-1">Direction</label>
                      <Select value={direction} onValueChange={(val: any) => setDirection(val)}>
                        <SelectTrigger className="bg-black/40 border-white/5 h-12 font-bold"><SelectValue /></SelectTrigger>
                        <SelectContent>
                          <SelectItem value="Buy">BUY</SelectItem>
                          <SelectItem value="Sell">SELL</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                    <div className="space-y-1">
                      <label className="text-[8px] font-black uppercase text-muted-foreground ml-1">Entry</label>
                      <Input value={entry} onChange={(e) => setEntry(e.target.value)} placeholder="4525.50" className="bg-black/40 border-white/5 h-12" />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[8px] font-black uppercase text-muted-foreground ml-1">Take Profit</label>
                      <Input value={tp} onChange={(e) => setTp(e.target.value)} placeholder="4650.00" className="bg-black/40 border-white/5 h-12 text-success" />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[8px] font-black uppercase text-muted-foreground ml-1">Stop Loss</label>
                      <Input value={sl} onChange={(e) => setSl(e.target.value)} placeholder="4480.00" className="bg-black/40 border-white/5 h-12 text-destructive" />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[8px] font-black uppercase text-muted-foreground ml-1">Confidence %</label>
                      <Input defaultValue="94" className="bg-black/40 border-white/5 h-12" />
                    </div>
                    <div className="col-span-2 space-y-1">
                      <label className="text-[8px] font-black uppercase text-muted-foreground ml-1">Reasoning / Analysis</label>
                      <Input value={reason} onChange={(e) => setReason(e.target.value)} placeholder="Analysis for APRIL 2026..." className="bg-black/40 border-white/5 h-12" />
                    </div>
                  </div>
                  <Button onClick={handleBroadcast} disabled={broadcastLoading} className="w-full h-14 bg-primary text-black font-black uppercase tracking-widest text-[10px]">
                    {broadcastLoading ? <Loader2 className="h-5 w-5 animate-spin" /> : 'Broadcast Live Signal'}
                  </Button>
                  <Button variant="ghost" onClick={handleSeedData} className="w-full h-10 text-[9px] font-black uppercase tracking-widest text-muted-foreground hover:text-white">
                    Seed APRIL 2026 Data Feed
                  </Button>
                </Card>

                <Card className="bg-white/5 border-white/10 p-6 space-y-6 rounded-3xl">
                  <h3 className="font-black text-lg uppercase tracking-tight flex items-center gap-2">
                    <Activity className="h-5 w-5 text-accent" /> Active Market Feed
                  </h3>
                  <div className="space-y-3 max-h-[450px] overflow-y-auto pr-2 custom-scrollbar">
                    {liveSignals?.map(sig => (
                      <div key={sig.id} className="p-4 rounded-2xl bg-black/40 border border-white/5 flex items-center justify-between group hover:border-primary/20 transition-all">
                        <div className="flex items-center gap-4">
                          <div className={`h-10 w-10 rounded-xl flex items-center justify-center ${sig.direction === 'Buy' ? 'bg-success/10' : 'bg-destructive/10'}`}>
                            <BarChart2 className={`h-5 w-5 ${sig.direction === 'Buy' ? 'text-success' : 'text-destructive'}`} />
                          </div>
                          <div>
                            <p className="font-black text-sm">{sig.asset} | {sig.direction.toUpperCase()}</p>
                            <p className="text-[9px] text-muted-foreground uppercase font-bold">Price: {sig.entryPrice}</p>
                          </div>
                        </div>
                        <Button variant="ghost" size="sm" onClick={() => handleDeleteSignal(sig.id)} className="text-destructive hover:bg-destructive/10 opacity-40 group-hover:opacity-100 transition-opacity">
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    ))}
                  </div>
                </Card>
              </div>
            </TabsContent>

            <TabsContent value="users" className="space-y-8">
              <div className="flex gap-4 p-6 bg-white/5 rounded-3xl border border-white/5">
                <div className="relative flex-1">
                  <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                  <Input placeholder="Enter Trader Email to Manage..." value={userSearch} onChange={(e) => setUserSearch(e.target.value)} className="bg-black/40 h-14 pl-12 border-white/10 font-bold" />
                </div>
                <Button onClick={handleSearchUser} disabled={searching} className="bg-primary text-black font-black uppercase px-10 h-14 rounded-2xl">
                  {searching ? <Loader2 className="h-5 w-5 animate-spin" /> : 'Identify Trader'}
                </Button>
              </div>

              <div className="space-y-4">
                {foundUsers.map((user) => (
                  <Card key={user.uid} className="bg-white/5 border-white/10 p-8 flex flex-col md:flex-row items-center justify-between rounded-3xl gap-6">
                    <div className="flex items-center gap-6">
                      <div className="h-16 w-16 rounded-2xl bg-black border border-white/10 flex items-center justify-center text-xl font-black text-primary uppercase">
                        {user.name ? user.name[0] : 'T'}
                      </div>
                      <div className="space-y-1">
                        <div className="flex items-center gap-3">
                          <p className="font-black text-xl tracking-tighter uppercase">{user.name || 'Anonymous'}</p>
                          <Badge variant="outline" className={user.isSubscribed ? "bg-amber-500/10 text-amber-500 border-amber-500/30 font-black uppercase text-[8px]" : "font-black uppercase text-[8px]"}>
                            {user.isSubscribed ? "INSTITUTIONAL VIP" : "FREE MEMBER"}
                          </Badge>
                        </div>
                        <p className="text-xs font-bold text-muted-foreground flex items-center gap-2">
                           <Users className="h-3 w-3" /> {user.email}
                        </p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3">
                      <Button 
                        onClick={() => toggleUserVip(user.uid, user.isSubscribed)} 
                        className={user.isSubscribed ? "bg-destructive/10 text-destructive border border-destructive/30 hover:bg-destructive/20 h-12 px-6 rounded-xl font-black uppercase text-[10px]" : "bg-success text-black h-12 px-8 rounded-xl font-black uppercase text-[10px] shadow-lg shadow-success/20"}
                        size="sm"
                      >
                        {user.isSubscribed ? "Revoke VIP Terminal" : "Approve VIP Access"}
                      </Button>
                    </div>
                  </Card>
                ))}
              </div>
            </TabsContent>
          </Tabs>
        </div>
      </DialogContent>
    </Dialog>
  );
};
