
"use client"

import React, { useEffect, useRef, memo, useState } from 'react';
import { TrendingUp, TrendingDown, Lock, Eye } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { AISignalOutput } from '@/ai/flows/ai-signal-generation';
import { cn } from '@/lib/utils';

interface SignalCardProps {
  symbol: string;
  type: 'Forex' | 'Crypto';
  signal: AISignalOutput;
  isLocked?: boolean;
  onUnlock?: () => void;
  onUpgradeClick?: () => void;
}

export const SignalCard = memo(({ symbol, type, signal, isLocked, onUnlock, onUpgradeClick }: SignalCardProps) => {
  const isBuy = signal.direction === 'Buy';
  const gaugeRef = useRef<HTMLDivElement>(null);
  const currentSymbolRef = useRef<string | null>(null);
  const [isWidgetLoading, setIsWidgetLoading] = useState(false);
  
  useEffect(() => {
    if (!gaugeRef.current || isLocked) {
      currentSymbolRef.current = null;
      return;
    }
    
    if (currentSymbolRef.current === symbol) return;

    setIsWidgetLoading(true);
    const container = gaugeRef.current;
    container.innerHTML = "";

    const script = document.createElement("script");
    script.src = "https://s3.tradingview.com/external-embedding/embed-widget-technical-analysis.js";
    script.type = "text/javascript";
    script.async = true;
    
    let tvSymbol = symbol;
    if (type === 'Forex') {
      tvSymbol = `FX:${symbol.replace('/', '')}`;
      if (symbol === 'GOLD' || symbol === 'XAUUSD') tvSymbol = 'OANDA:XAUUSD';
    } else {
      tvSymbol = `BINANCE:${symbol}USDT`;
    }

    script.innerHTML = JSON.stringify({
      "interval": "1h",
      "width": "100%",
      "isTransparent": true,
      "height": "100%",
      "symbol": tvSymbol,
      "showIntervalTabs": false,
      "displayMode": "single",
      "locale": "en",
      "colorTheme": "dark"
    });
    
    script.onload = () => setIsWidgetLoading(false);
    container.appendChild(script);
    currentSymbolRef.current = symbol;

    return () => {
      if (container) container.innerHTML = "";
    };
  }, [symbol, type, isLocked]);
  
  return (
    <Card className={cn(
      "relative overflow-hidden border-white/5 bg-card/40 glassmorphism transition-all duration-300 rounded-3xl gpu-stable",
      "min-h-[440px] h-full" 
    )}>
      <div className={cn(
        "absolute top-0 left-0 w-1.5 h-full z-20",
        isBuy ? 'bg-success shadow-[0_0_15px_rgba(16,185,129,0.5)]' : 'bg-destructive shadow-[0_0_15px_rgba(239,68,68,0.5)]'
      )} />
      
      <CardHeader className="flex flex-row items-center justify-between pb-4 p-5 relative z-10">
        <div className="space-y-1">
          <CardTitle className="text-xl font-black flex items-center gap-2 tracking-tighter">
            {symbol}
            <Badge variant="outline" className="text-[8px] uppercase font-black bg-white/5 px-1.5 py-0">
              {type}
            </Badge>
          </CardTitle>
          <p className="text-[8px] text-muted-foreground/60 uppercase tracking-widest font-black">AI Analysis Active</p>
        </div>
        {!isLocked && (
          <div className={cn(
            "flex items-center gap-1.5 font-black text-lg tracking-tighter px-3 py-1 rounded-xl bg-white/5",
            isBuy ? 'text-success neon-text-emerald' : 'text-destructive neon-text-crimson'
          )}>
            {isBuy ? <TrendingUp className="h-4 w-4" /> : <TrendingDown className="h-4 w-4" />}
            {signal.direction.toUpperCase()}
          </div>
        )}
      </CardHeader>

      <CardContent className="space-y-4 p-5 pt-0 relative h-full flex flex-col">
        {isLocked ? (
          <div className="absolute inset-0 z-50 flex flex-col items-center justify-center p-6 text-center bg-black/60 backdrop-blur-xl rounded-3xl gpu-stable animate-in fade-in duration-300">
            <div className="h-16 w-16 rounded-2xl bg-primary/10 border border-primary/20 flex items-center justify-center mb-6">
              <Lock className="h-8 w-8 text-primary" />
            </div>
            <h3 className="text-lg font-black uppercase tracking-tighter text-white mb-2">Locked Signal</h3>
            <p className="text-[9px] text-muted-foreground uppercase font-black tracking-widest mb-6">Standard Terminal Cost: 1 Credit</p>
            <Button onClick={onUnlock} className="h-12 w-full bg-primary text-black font-black uppercase text-xs tracking-widest rounded-xl shadow-lg shadow-primary/20">
              <Eye className="h-4 w-4 mr-2" /> Reveal Now
            </Button>
            <Button onClick={onUpgradeClick} variant="ghost" className="text-amber-500 font-black uppercase text-[8px] tracking-[0.2em] mt-2">
              Upgrade to VIP
            </Button>
          </div>
        ) : (
          <div className="animate-in fade-in zoom-in-95 duration-500">
            <div className="grid grid-cols-3 gap-2 p-4 rounded-2xl bg-black/40 border border-white/5">
              <div>
                <p className="text-[8px] text-muted-foreground uppercase font-black tracking-widest mb-1">Entry</p>
                <p className="text-xs font-mono font-bold">{signal.entryPrice.toLocaleString()}</p>
              </div>
              <div className="border-x border-white/5 px-2 text-center">
                <p className="text-[8px] text-accent uppercase font-black tracking-widest mb-1">Target</p>
                <p className="text-xs font-mono font-bold text-accent">{signal.takeProfit.toLocaleString()}</p>
              </div>
              <div className="text-right">
                <p className="text-[8px] text-destructive uppercase font-black tracking-widest mb-1">Risk</p>
                <p className="text-xs font-mono font-bold text-destructive">{signal.stopLoss.toLocaleString()}</p>
              </div>
            </div>

            <div className="h-48 border border-white/5 rounded-2xl bg-black/40 overflow-hidden relative mt-4">
              <div ref={gaugeRef} className="w-full h-full" />
              {isWidgetLoading && (
                <div className="absolute inset-0 flex items-center justify-center bg-black/20 backdrop-blur-sm">
                  <div className="h-6 w-6 border-2 border-primary border-t-transparent rounded-full animate-spin" />
                </div>
              )}
            </div>

            <div className="space-y-2 mt-4">
              <div className="flex justify-between items-center text-[9px] font-black uppercase">
                <span className="text-muted-foreground">Confidence</span>
                <span className="text-primary">{signal.confidenceScore}%</span>
              </div>
              <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-primary rounded-full transition-all duration-1000 shadow-[0_0_10px_rgba(139,92,246,0.3)]" 
                  style={{ width: `${signal.confidenceScore}%` }} 
                />
              </div>
            </div>

            <p className="text-[9px] text-muted-foreground/80 leading-relaxed italic line-clamp-2 mt-4">
              {signal.reasoning}
            </p>
          </div>
        )}
      </CardContent>
    </Card>
  );
});
SignalCard.displayName = 'SignalCard';
